-- CREATE A SIMPLE FCT SALES TABLE WITH HASH DISTRIBUTION

CREATE TABLE SALES_HASH
(
    CUST_ID INT,
    PROD_ID INT,
    AMOUNT INT
)
WITH (
    DISTRIBUTION = HASH(CUST_ID),
    CLUSTERED COLUMNSTORE INDEX
);

-- CREATE THE SAME FCT SALES TABLE WITH ROUND ROBIN DISTRIBUTION
CREATE TABLE SALES_RR
(
    CUST_ID INT,
    PROD_ID INT,
    AMOUNT INT
)
WITH (
    DISTRIBUTION = ROUND_ROBIN,
    CLUSTERED COLUMNSTORE INDEX
);

-- CREATE A SIMPLE DIM PRODUCT TABLE USING REPLICATE DISTRIBUTION

CREATE TABLE PRODUCT
(
    PROD_ID INT,
    PROD_NAME VARCHAR(100)
)
WITH (
    DISTRIBUTION = REPLICATE
);


