-- CHECK THE DISTRIBUTION FOR THE ABOVE TABLES

SELECT
tbl.name,
tbl.object_id,
p.distribution_policy_desc
FROM sys.tables tbl
JOIN sys.pdw_table_distribution_properties p
ON tbl.object_id = p.object_id;

SELECT 
OBJECT_NAME(OBJECT_ID) as table_name,
ps.distribution_id,
ps.row_count
FROM sys.dm_pdw_nodes_db_partition_stats ps
WHERE row_count <> 0 AND OBJECT_NAME(OBJECT_ID) IS  NOT NULL;

